import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Présentation du Plugin : Fonctionnalités et Risques | Antigravity Auth","description":"Découvrez la valeur fondamentale et les avertissements de risques du plugin Antigravity Auth. Accédez aux modèles Claude et Gemini 3 via Google OAuth, avec équilibrage de charge multi-comptes.","frontmatter":{"title":"Présentation du Plugin : Fonctionnalités et Risques | Antigravity Auth","sidebarTitle":"Ce plugin est-il fait pour vous ?","subtitle":"Découvrez la valeur fondamentale du plugin Antigravity Auth","description":"Découvrez la valeur fondamentale et les avertissements de risques du plugin Antigravity Auth. Accédez aux modèles Claude et Gemini 3 via Google OAuth, avec équilibrage de charge multi-comptes.","tags":["Démarrage","Présentation du plugin","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"fr/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"fr/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),s={name:"fr/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function n(l,e,r,u,d,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="decouvrez-la-valeur-fondamentale-du-plugin-antigravity-auth" tabindex="-1">Découvrez la valeur fondamentale du plugin Antigravity Auth <a class="header-anchor" href="#decouvrez-la-valeur-fondamentale-du-plugin-antigravity-auth" aria-label="Permalink to &quot;Découvrez la valeur fondamentale du plugin Antigravity Auth&quot;">​</a></h1><p><strong>Antigravity Auth</strong> est un plugin OpenCode qui accède à l&#39;API Antigravity via l&#39;authentification Google OAuth. Il vous permet d&#39;utiliser votre compte Google habituel pour appeler des modèles avancés comme Claude Opus 4.5, Sonnet 4.5 et Gemini 3 Pro/Flash, sans avoir à gérer de clés API. Le plugin offre également l&#39;équilibrage de charge multi-comptes, un double pool de quotas et la récupération automatique de session, idéal pour les utilisateurs ayant besoin de modèles avancés et d&#39;une gestion automatisée.</p><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que vous apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que vous apprendrez&quot;">​</a></h2><ul><li>Déterminer si ce plugin correspond à votre cas d&#39;utilisation</li><li>Connaître les modèles IA et fonctionnalités principales supportés</li><li>Comprendre les risques et précautions liés à l&#39;utilisation de ce plugin</li><li>Décider si vous souhaitez poursuivre l&#39;installation et la configuration</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Vous souhaitez utiliser les modèles IA les plus avancés (comme Claude Opus 4.5, Gemini 3 Pro), mais l&#39;accès officiel est limité. Vous cherchez un moyen fiable d&#39;accéder à ces modèles, tout en espérant :</p><ul><li>Ne pas avoir à gérer manuellement plusieurs clés API</li><li>Basculer automatiquement vers un autre compte en cas de limite de débit</li><li>Récupérer automatiquement après une interruption de conversation, sans perdre le contexte</li></ul><h2 id="concept-fondamental" tabindex="-1">Concept fondamental <a class="header-anchor" href="#concept-fondamental" aria-label="Permalink to &quot;Concept fondamental&quot;">​</a></h2><p><strong>Antigravity Auth</strong> est un plugin OpenCode qui accède à l&#39;API Google Antigravity via <strong>l&#39;authentification Google OAuth</strong>, vous permettant d&#39;appeler des modèles IA avancés avec votre compte Google habituel.</p><p>Il ne s&#39;agit pas d&#39;un proxy pour toutes les requêtes, mais d&#39;une <strong>interception et transformation</strong> de vos appels de modèles, les redirigeant vers l&#39;API Antigravity, puis convertissant les réponses dans un format reconnaissable par OpenCode.</p><h2 id="fonctionnalites-principales" tabindex="-1">Fonctionnalités principales <a class="header-anchor" href="#fonctionnalites-principales" aria-label="Permalink to &quot;Fonctionnalités principales&quot;">​</a></h2><h3 id="modeles-supportes" tabindex="-1">Modèles supportés <a class="header-anchor" href="#modeles-supportes" aria-label="Permalink to &quot;Modèles supportés&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Famille de modèles</th><th>Modèles disponibles</th><th>Caractéristiques</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>Support du mode réflexion étendue</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Intégration Google Search, réflexion étendue</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Mode Réflexion (Thinking)</p><p>Les modèles Thinking effectuent une « réflexion approfondie » avant de générer une réponse, affichant le processus de raisonnement. Vous pouvez configurer le budget de réflexion pour équilibrer qualité et vitesse de réponse.</p></div><h3 id="equilibrage-de-charge-multi-comptes" tabindex="-1">Équilibrage de charge multi-comptes <a class="header-anchor" href="#equilibrage-de-charge-multi-comptes" aria-label="Permalink to &quot;Équilibrage de charge multi-comptes&quot;">​</a></h3><ul><li><strong>Support jusqu&#39;à 10 comptes Google</strong></li><li>Basculement automatique vers le compte suivant en cas de limite de débit (erreur 429)</li><li>Trois stratégies de sélection de compte : sticky (fixe), round-robin (rotation), hybrid (mixte intelligent)</li></ul><h3 id="systeme-de-double-quota" tabindex="-1">Système de double quota <a class="header-anchor" href="#systeme-de-double-quota" aria-label="Permalink to &quot;Système de double quota&quot;">​</a></h3><p>Le plugin accède simultanément à <strong>deux pools de quotas indépendants</strong> :</p><ol><li><strong>Quota Antigravity</strong> : provenant de l&#39;API Google Antigravity</li><li><strong>Quota Gemini CLI</strong> : provenant de Google Gemini CLI</li></ol><p>Lorsqu&#39;un pool est limité, le plugin essaie automatiquement l&#39;autre, maximisant l&#39;utilisation des quotas.</p><h3 id="recuperation-automatique-de-session" tabindex="-1">Récupération automatique de session <a class="header-anchor" href="#recuperation-automatique-de-session" aria-label="Permalink to &quot;Récupération automatique de session&quot;">​</a></h3><ul><li>Détection des échecs d&#39;appels d&#39;outils (comme l&#39;interruption par ESC)</li><li>Injection automatique d&#39;un tool_result synthétique pour éviter le crash de la conversation</li><li>Support de l&#39;envoi automatique de &quot;continue&quot; pour poursuivre la conversation</li></ul><h3 id="integration-google-search" tabindex="-1">Intégration Google Search <a class="header-anchor" href="#integration-google-search" aria-label="Permalink to &quot;Intégration Google Search&quot;">​</a></h3><p>Activez la recherche web pour les modèles Gemini, améliorant la précision factuelle :</p><ul><li><strong>Mode Auto</strong> : le modèle décide s&#39;il doit effectuer une recherche selon les besoins</li><li><strong>Mode Always-on</strong> : recherche systématique à chaque requête</li></ul><h2 id="quand-utiliser-ce-plugin" tabindex="-1">Quand utiliser ce plugin <a class="header-anchor" href="#quand-utiliser-ce-plugin" aria-label="Permalink to &quot;Quand utiliser ce plugin&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Adapté aux scénarios suivants</p><ul><li>Vous avez plusieurs comptes Google et souhaitez augmenter votre quota total</li><li>Vous avez besoin des modèles Thinking de Claude ou Gemini 3</li><li>Vous souhaitez activer Google Search pour les modèles Gemini</li><li>Vous préférez l&#39;authentification OAuth à la gestion manuelle des clés API</li><li>Vous rencontrez souvent des limites de débit et souhaitez un basculement automatique de compte</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Non adapté aux scénarios suivants</p><ul><li>Vous avez besoin de modèles non publics de Google</li><li>Vous êtes très sensible aux risques liés aux CGU de Google (voir avertissement ci-dessous)</li><li>Vous n&#39;avez besoin que des modèles basiques Gemini 1.5 ou Claude 3 (les interfaces officielles sont plus stables)</li><li>Vous avez des difficultés à ouvrir un navigateur dans des environnements WSL, Docker, etc.</li></ul></div><h2 id="⚠️-avertissement-important-sur-les-risques" tabindex="-1">⚠️ Avertissement important sur les risques <a class="header-anchor" href="#⚠️-avertissement-important-sur-les-risques" aria-label="Permalink to &quot;⚠️ Avertissement important sur les risques&quot;">​</a></h2><p>L&#39;utilisation de ce plugin <strong>peut violer les conditions d&#39;utilisation de Google</strong>. Quelques utilisateurs ont signalé que leur compte Google a été <strong>banni</strong> ou <strong>shadow-banni</strong> (accès restreint sans notification explicite).</p><h3 id="scenarios-a-haut-risque" tabindex="-1">Scénarios à haut risque <a class="header-anchor" href="#scenarios-a-haut-risque" aria-label="Permalink to &quot;Scénarios à haut risque&quot;">​</a></h3><ul><li>🚨 <strong>Nouveaux comptes Google</strong> : probabilité de bannissement très élevée</li><li>🚨 <strong>Comptes avec abonnement Pro/Ultra récent</strong> : facilement signalés et bannis</li></ul><h3 id="avant-d-utiliser-veuillez-confirmer" tabindex="-1">Avant d&#39;utiliser, veuillez confirmer <a class="header-anchor" href="#avant-d-utiliser-veuillez-confirmer" aria-label="Permalink to &quot;Avant d&#39;utiliser, veuillez confirmer&quot;">​</a></h3><ul><li>Il s&#39;agit d&#39;un <strong>outil non officiel</strong>, non approuvé par Google</li><li>Votre compte peut être suspendu ou banni définitivement</li><li>Vous assumez tous les risques liés à l&#39;utilisation de ce plugin</li></ul><h3 id="recommandations" tabindex="-1">Recommandations <a class="header-anchor" href="#recommandations" aria-label="Permalink to &quot;Recommandations&quot;">​</a></h3><ul><li>Utilisez des <strong>comptes Google établis</strong>, plutôt que de créer de nouveaux comptes pour ce plugin</li><li>Évitez d&#39;utiliser des comptes importants liés à des services critiques</li><li>En cas de bannissement, il n&#39;est pas possible de faire appel via ce plugin</li></ul><div class="danger custom-block"><p class="custom-block-title">Sécurité du compte</p><p>Tous les tokens OAuth sont stockés localement dans <code>~/.config/opencode/antigravity-accounts.json</code> et ne sont jamais téléchargés vers un serveur. Cependant, assurez-vous que votre ordinateur est sécurisé pour éviter toute fuite de tokens.</p></div><h2 id="resume-de-cette-lecon" tabindex="-1">Résumé de cette leçon <a class="header-anchor" href="#resume-de-cette-lecon" aria-label="Permalink to &quot;Résumé de cette leçon&quot;">​</a></h2><p>Antigravity Auth est un puissant plugin OpenCode qui vous permet d&#39;accéder aux modèles avancés Claude et Gemini 3 via Google OAuth. Il offre l&#39;équilibrage de charge multi-comptes, un double pool de quotas, la récupération automatique de session et d&#39;autres fonctionnalités, idéal pour les utilisateurs ayant besoin de modèles avancés et d&#39;une gestion automatisée.</p><p>Mais attention : <strong>l&#39;utilisation de ce plugin comporte un risque de bannissement de compte</strong>. Veuillez utiliser des comptes Google non critiques et comprendre les risques associés avant de poursuivre l&#39;installation.</p><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons l&#39;<strong><a href="./../quick-install/">Installation rapide</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Installer le plugin en 5 minutes</li><li>Ajouter votre premier compte Google</li><li>Vérifier que l&#39;installation a réussi</li></ul></blockquote>',42)])])}const h=t(s,[["render",n]]);export{m as __pageData,h as default};
